import{_ as e,o as l,c as i,ak as r}from"./chunks/framework.B_unCYUt.js";const m=JSON.parse('{"title":"高等数学","description":"","frontmatter":{},"headers":[],"relativePath":"Courses/高等数学.md","filePath":"Courses/高等数学.md","lastUpdated":1729756988000}'),h={name:"Courses/高等数学.md"};function n(d,a,t,s,o,c){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="高等数学" tabindex="-1">高等数学 <a class="header-anchor" href="#高等数学" aria-label="Permalink to “高等数学”">​</a></h1><h2 id="核心知识" tabindex="-1">核心知识 <a class="header-anchor" href="#核心知识" aria-label="Permalink to “核心知识”">​</a></h2><p>空间解析几何与向量代数、多元函数的微分学、重积分、曲线积分与曲面积分、常微分方程以及无穷级数等内容.</p><p>做习题, 掌握基本概念、基本理论和基本运算, 会用所学知识解决某些简单的实际问题, 为学习后续课程打好必要基础.</p><h1 id="空间解析几何与向量代数" tabindex="-1">空间解析几何与向量代数 <a class="header-anchor" href="#空间解析几何与向量代数" aria-label="Permalink to “空间解析几何与向量代数”">​</a></h1><h2 id="核心知识-1" tabindex="-1">核心知识 <a class="header-anchor" href="#核心知识-1" aria-label="Permalink to “核心知识”">​</a></h2><ul><li>空间直角坐标系</li><li>向量的概念及其线性运算</li><li>向量的坐标</li><li>向量的数量积</li><li>平面方程</li><li>直线方程</li><li>曲面方程</li><li>曲线方程</li><li>二次曲面</li></ul><h3 id="重点与难点" tabindex="-1">重点与难点 <a class="header-anchor" href="#重点与难点" aria-label="Permalink to “重点与难点”">​</a></h3><p>重点: 向量的各种运算, 平面、直线, 柱面, 旋转面及二次去面壁的标准方程及其图形.</p><p>难点: 向量的运算, 空间曲线在坐标面上的投影</p><h2 id="空间直角坐标系" tabindex="-1">空间直角坐标系 <a class="header-anchor" href="#空间直角坐标系" aria-label="Permalink to “空间直角坐标系”">​</a></h2><h2 id="向量代数" tabindex="-1">向量代数 <a class="header-anchor" href="#向量代数" aria-label="Permalink to “向量代数”">​</a></h2><h2 id="向量的数量积与向量积" tabindex="-1">向量的数量积与向量积 <a class="header-anchor" href="#向量的数量积与向量积" aria-label="Permalink to “向量的数量积与向量积”">​</a></h2><h2 id="空间中的曲面和曲线" tabindex="-1">空间中的曲面和曲线 <a class="header-anchor" href="#空间中的曲面和曲线" aria-label="Permalink to “空间中的曲面和曲线”">​</a></h2><h2 id="空间中的平面与直线" tabindex="-1">空间中的平面与直线 <a class="header-anchor" href="#空间中的平面与直线" aria-label="Permalink to “空间中的平面与直线”">​</a></h2><h2 id="二次曲面" tabindex="-1">二次曲面 <a class="header-anchor" href="#二次曲面" aria-label="Permalink to “二次曲面”">​</a></h2><h1 id="多元函数的微分学" tabindex="-1">多元函数的微分学 <a class="header-anchor" href="#多元函数的微分学" aria-label="Permalink to “多元函数的微分学”">​</a></h1><h2 id="知识点" tabindex="-1">知识点 <a class="header-anchor" href="#知识点" aria-label="Permalink to “知识点”">​</a></h2><ul><li>多元函数的概念</li><li>二元函数的极限与连续</li><li>偏导数</li><li>高阶偏导数</li><li>方向导数和梯度</li><li>全微分</li><li>复合函数求导法则</li><li>隐函数求导法则</li><li>空间曲线的切线与法平面、曲面的切平面与法线,</li><li>二元函数的极值</li></ul><h3 id="重点与难点-1" tabindex="-1">重点与难点 <a class="header-anchor" href="#重点与难点-1" aria-label="Permalink to “重点与难点”">​</a></h3><p>重点: 偏导数, 极值及其应用</p><p>难点: 复合函数的偏导数, 求多元函数极值的方法及其应用</p><h2 id="多元函数的基本概念" tabindex="-1">多元函数的基本概念 <a class="header-anchor" href="#多元函数的基本概念" aria-label="Permalink to “多元函数的基本概念”">​</a></h2><h2 id="偏导数与全微分" tabindex="-1">偏导数与全微分 <a class="header-anchor" href="#偏导数与全微分" aria-label="Permalink to “偏导数与全微分”">​</a></h2><h2 id="复合函数与隐函数的导数和偏导数" tabindex="-1">复合函数与隐函数的导数和偏导数 <a class="header-anchor" href="#复合函数与隐函数的导数和偏导数" aria-label="Permalink to “复合函数与隐函数的导数和偏导数”">​</a></h2><h2 id="偏导数的应用" tabindex="-1">偏导数的应用 <a class="header-anchor" href="#偏导数的应用" aria-label="Permalink to “偏导数的应用”">​</a></h2><h1 id="重积分" tabindex="-1">重积分 <a class="header-anchor" href="#重积分" aria-label="Permalink to “重积分”">​</a></h1><h2 id="知识点-1" tabindex="-1">知识点 <a class="header-anchor" href="#知识点-1" aria-label="Permalink to “知识点”">​</a></h2><ul><li>二重积分和三重积分的定义与性质</li><li>二重积分的计算</li><li>三重积分的计算</li><li>重积分的应用</li></ul><h3 id="重点与难点-2" tabindex="-1">重点与难点 <a class="header-anchor" href="#重点与难点-2" aria-label="Permalink to “重点与难点”">​</a></h3><p>重点: 重积分的计算</p><p>难点: 重积分化为累次积分</p><h2 id="二重积分" tabindex="-1">二重积分 <a class="header-anchor" href="#二重积分" aria-label="Permalink to “二重积分”">​</a></h2><h2 id="三重积分" tabindex="-1">三重积分 <a class="header-anchor" href="#三重积分" aria-label="Permalink to “三重积分”">​</a></h2><h2 id="重积分的应用" tabindex="-1">重积分的应用 <a class="header-anchor" href="#重积分的应用" aria-label="Permalink to “重积分的应用”">​</a></h2><h1 id="曲线积分与曲面积分" tabindex="-1">曲线积分与曲面积分 <a class="header-anchor" href="#曲线积分与曲面积分" aria-label="Permalink to “曲线积分与曲面积分”">​</a></h1><h2 id="知识点-2" tabindex="-1">知识点 <a class="header-anchor" href="#知识点-2" aria-label="Permalink to “知识点”">​</a></h2><ul><li>两类曲线积分的定义与性质</li><li>两类曲线积分的计算</li><li>格林公式</li><li>平面曲线积分与路径无关的条件</li><li>两类曲面积分的定义与性质</li><li>两类曲面积分的计算</li></ul><h3 id="重点与难点-3" tabindex="-1">重点与难点 <a class="header-anchor" href="#重点与难点-3" aria-label="Permalink to “重点与难点”">​</a></h3><p>重点: 曲线积分和曲面积分的概念及计算, 格林公式</p><p>难点: 对坐标的曲线积分与曲面积分的计算, 平面曲线积分与路径无关的条件</p><h2 id="对弧长的曲线积分" tabindex="-1">对弧长的曲线积分 <a class="header-anchor" href="#对弧长的曲线积分" aria-label="Permalink to “对弧长的曲线积分”">​</a></h2><h2 id="对坐标的曲线积分" tabindex="-1">对坐标的曲线积分 <a class="header-anchor" href="#对坐标的曲线积分" aria-label="Permalink to “对坐标的曲线积分”">​</a></h2><h2 id="格林公式及其应用" tabindex="-1">格林公式及其应用 <a class="header-anchor" href="#格林公式及其应用" aria-label="Permalink to “格林公式及其应用”">​</a></h2><h2 id="对面积的曲面积分" tabindex="-1">对面积的曲面积分 <a class="header-anchor" href="#对面积的曲面积分" aria-label="Permalink to “对面积的曲面积分”">​</a></h2><h2 id="对坐标的曲面积分" tabindex="-1">对坐标的曲面积分 <a class="header-anchor" href="#对坐标的曲面积分" aria-label="Permalink to “对坐标的曲面积分”">​</a></h2><h1 id="常微分方程" tabindex="-1">常微分方程 <a class="header-anchor" href="#常微分方程" aria-label="Permalink to “常微分方程”">​</a></h1><h2 id="知识点-3" tabindex="-1">知识点 <a class="header-anchor" href="#知识点-3" aria-label="Permalink to “知识点”">​</a></h2><ul><li>微分方程的一般概念</li><li>三类一阶微分方程</li><li>三类可降阶的二阶微分方程</li><li>二阶线性微分方程解的结构</li><li>二阶常系数线性齐次微分方程</li></ul><h3 id="重点与难点-4" tabindex="-1">重点与难点 <a class="header-anchor" href="#重点与难点-4" aria-label="Permalink to “重点与难点”">​</a></h3><p>重点: 三类一阶微分方程, 二阶常系数线性齐次微分方程</p><p>难点: 微分方程类型的识别, 二元一次方程的复根</p><h2 id="微分方程的基本概念" tabindex="-1">微分方程的基本概念 <a class="header-anchor" href="#微分方程的基本概念" aria-label="Permalink to “微分方程的基本概念”">​</a></h2><h2 id="一阶微分方程" tabindex="-1">一阶微分方程 <a class="header-anchor" href="#一阶微分方程" aria-label="Permalink to “一阶微分方程”">​</a></h2><h2 id="可降阶的二级微分方程" tabindex="-1">可降阶的二级微分方程 <a class="header-anchor" href="#可降阶的二级微分方程" aria-label="Permalink to “可降阶的二级微分方程”">​</a></h2><h2 id="二阶线性微分方程解的结构" tabindex="-1">二阶线性微分方程解的结构 <a class="header-anchor" href="#二阶线性微分方程解的结构" aria-label="Permalink to “二阶线性微分方程解的结构”">​</a></h2><h2 id="二阶常系数线性微分方程" tabindex="-1">二阶常系数线性微分方程 <a class="header-anchor" href="#二阶常系数线性微分方程" aria-label="Permalink to “二阶常系数线性微分方程”">​</a></h2><h1 id="无穷级数" tabindex="-1">无穷级数 <a class="header-anchor" href="#无穷级数" aria-label="Permalink to “无穷级数”">​</a></h1><h2 id="知识点-4" tabindex="-1">知识点 <a class="header-anchor" href="#知识点-4" aria-label="Permalink to “知识点”">​</a></h2><ul><li>数项级数的基本概念</li><li>数项级数的性质</li><li>正项级数及其审敛法</li><li>一般项级数的审敛法</li><li>幂级数的收敛性及和函数的性质</li><li>函数的泰勒级数展开式</li><li>傅里叶级数</li></ul><h3 id="重点与难点-5" tabindex="-1">重点与难点 <a class="header-anchor" href="#重点与难点-5" aria-label="Permalink to “重点与难点”">​</a></h3><p>重点: 数项级数、幂级数,将函数展开成泰勒级数</p><p>难点: 数项级数收敛散性的判定, 用间接法将函数展开为幂级数</p><h2 id="数项级数的概念及其基本性质" tabindex="-1">数项级数的概念及其基本性质 <a class="header-anchor" href="#数项级数的概念及其基本性质" aria-label="Permalink to “数项级数的概念及其基本性质”">​</a></h2><h2 id="数项级数的审敛法" tabindex="-1">数项级数的审敛法 <a class="header-anchor" href="#数项级数的审敛法" aria-label="Permalink to “数项级数的审敛法”">​</a></h2><h2 id="幂级数" tabindex="-1">幂级数 <a class="header-anchor" href="#幂级数" aria-label="Permalink to “幂级数”">​</a></h2><h2 id="函数的幂级数展开式" tabindex="-1">函数的幂级数展开式 <a class="header-anchor" href="#函数的幂级数展开式" aria-label="Permalink to “函数的幂级数展开式”">​</a></h2><h2 id="傅里叶级数" tabindex="-1">傅里叶级数 <a class="header-anchor" href="#傅里叶级数" aria-label="Permalink to “傅里叶级数”">​</a></h2>',68)])])}const f=e(h,[["render",n]]);export{m as __pageData,f as default};
